+    fn make_pane_info() -> PaneInfo {
+        PaneInfo {
+            pane_id: 1,
+            tab_id: 1,
+            window_id: 1,
+            domain_id: None,
+            domain_name: None,
+            workspace: None,
+            size: None,
+            rows: None,
+            cols: None,
+            title: None,
+            cwd: None,
+            tty_name: None,
+            cursor_x: None,
+            cursor_y: None,
+            cursor_visibility: None,
+            left_col: None,
+            top_row: None,
+            is_active: false,
+            is_zoomed: false,
+            extra: std::collections::HashMap::new(),
+        }
+    }
+
+    #[test]
+    fn infer_pane_state_unknown_default() {
+        let info = make_pane_info();
+        assert_eq!(infer_pane_state(&info), "unknown");
