+        info.extra.insert(
+            "is_alt_screen_active".to_string(),
+            serde_json::Value::Bool(true),
+        );
+        assert_eq!(infer_pane_state(&info), "AltScreen");
+    }
+
+    #[test]
+    fn infer_pane_state_alt_screen_false() {
+        let mut info = make_pane_info();
